// Determine retry strategy based on error type and entity
const dlqItem = $input.first().json;
const entityData = $input.all()[1].json;

let retryStrategy = {
  shouldRetry: false,
  action: 'none',
  delayMinutes: 0,
  message: ''
};

const retryCount = dlqItem.retry_count || 0;
const maxRetries = 5;

// Calculate exponential backoff delay
const delayMinutes = Math.min(Math.pow(2, retryCount) * 5, 1440); // Cap at 24 hours

switch(dlqItem.entity_type) {
  case 'lead':
    // Lead processing errors - retry if data validation error
    if (dlqItem.error_type === 'validation_error' && retryCount < 2) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'reprocess_lead';
      retryStrategy.delayMinutes = delayMinutes;
      retryStrategy.message = 'Reprocessing lead after validation fix';
    } else if (dlqItem.error_type === 'database_error' && retryCount < 3) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'reinsert_lead';
      retryStrategy.delayMinutes = delayMinutes;
      retryStrategy.message = 'Retrying database insert';
    } else {
      retryStrategy.shouldRetry = false;
      retryStrategy.action = 'manual_review';
      retryStrategy.message = 'Requires manual review';
    }
    break;

  case 'lead_enrichment':
    // Enrichment errors - retry API failures
    if (dlqItem.error_type === 'api_error' && retryCount < 4) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'retry_enrichment';
      retryStrategy.delayMinutes = delayMinutes;
      retryStrategy.message = 'Retrying enrichment API call';
    } else if (dlqItem.error_type === 'rate_limit_error' && retryCount < maxRetries) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'retry_enrichment';
      retryStrategy.delayMinutes = 60; // Wait 1 hour for rate limit
      retryStrategy.message = 'Retrying after rate limit reset';
    } else {
      retryStrategy.shouldRetry = false;
      retryStrategy.action = 'mark_failed_permanent';
      retryStrategy.message = 'Max retries reached or permanent failure';
    }
    break;

  case 'lead_routing':
    // Routing errors - retry transient failures
    if (dlqItem.error_type === 'network_error' && retryCount < 3) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'retry_routing';
      retryStrategy.delayMinutes = delayMinutes;
      retryStrategy.message = 'Retrying routing due to network error';
    } else if (dlqItem.error_type === 'destination_error' && retryCount < 2) {
      retryStrategy.shouldRetry = true;
      retryStrategy.action = 'retry_routing';
      retryStrategy.delayMinutes = delayMinutes;
      retryStrategy.message = 'Retrying routing to destination';
    } else {
      retryStrategy.shouldRetry = false;
      retryStrategy.action = 'manual_review';
      retryStrategy.message = 'Requires manual review of destination';
    }
    break;

  default:
    retryStrategy.action = 'manual_review';
    retryStrategy.message = 'Unknown entity type';
}

return [{
  json: {
    dlqItem: dlqItem,
    entityData: entityData,
    retryStrategy: retryStrategy,
    shouldProceed: retryStrategy.shouldRetry && retryCount < maxRetries
  }
}];
